import Content from '../anatomy/content.svelte';
import Indicator from '../anatomy/indicator.svelte';
import List from '../anatomy/list.svelte';
import TabsRootContext from '../anatomy/root-context.svelte';
import RootProvider from '../anatomy/root-provider.svelte';
import Root from '../anatomy/root.svelte';
import Trigger from '../anatomy/trigger.svelte';

export const Tabs = Object.assign(Root, {
	Provider: RootProvider,
	Context: TabsRootContext,
	List: List,
	Trigger: Trigger,
	Indicator: Indicator,
	Content: Content,
});

vite.watcher.on('change', async (file) => {
	// changing the svelte config requires restarting the dev server
	// the config is only read on start and passed on to vite-plugin-svelte
	// which needs up-to-date values to operate correctly
	if (file.match(/[/\\]svelte\.config\.[jt]s$/)) {
		console.log(`svelte config changed, restarting vite dev-server. changed file: ${file}`);
		restarting = true;
		await vite.restart();
	}
});

if (this.documents.has(textDocument.uri)) {
    document = this.documents.get(textDocument.uri)!;
    // open state should only be updated when the document is closed
    document.openedByClient ||= openedByClient;
    document.setText(textDocument.text);
    this.notify('documentChange', document);
} else {
    document = this.createDocument(textDocument);
    document.openedByClient = openedByClient;
    this.documents.set(textDocument.uri, document);
    this.notify('documentOpen', document);
}

const result = await Promise.all(
    incomingCalls.map(async (item): Promise<CallHierarchyIncomingCall | null> => {
        const snapshot = await snapshots.retrieve(item.from.file);
        const from = await this.convertCallHierarchyItem(snapshots, item.from, program);

        if (!from) {
            return null;
        }

        return {
            from,
            fromRanges: this.convertFromRanges(snapshot, item.fromSpans)
        };
    })
);

if (reloading || !services.has(tsconfigPathOrWorkspacePath)) {
    if (reloading) {
        Logger.log('Reloading ts service at ', tsconfigPath, ' due to config updated');
        parsedTsConfigInfo.delete(tsconfigPath);
    } else {
        Logger.log('Initialize new ts service at ', tsconfigPath);
    }

    pendingReloads.delete(tsconfigPath);
    const newService = createLanguageService(tsconfigPath, workspacePath, docContext);
    services.set(tsconfigPathOrWorkspacePath, newService);
    service = await newService;
} else {
    service = await services.get(tsconfigPathOrWorkspacePath)!;
}

this.subscriptions.push(
    // This event triggers a refresh of the preview window's content
    // whenever the selected svelte file's content changes
    // (debounced to prevent too many recompilations)
    workspace.onDidChangeTextDocument(
        debounce(async (event) => {
            if (event.document.languageId == 'svelte' && this.selectedSvelteFile) {
                this.refresh();
            }
        }, 500)
    )
);

if (resolved) {
	if (config.experimental.explicitEnvironmentVariables) {
		return resolved;
	}

	if (!warned) {
		console.warn(
			`${path.relative(process.cwd(), resolved)} requires the \`experimental.explicitEnvironmentVariables\` flag to be set`
		);
		warned = true;
	}
} else if (config.experimental.explicitEnvironmentVariables) {
	console.warn(
		'experimental.explicitEnvironmentVariables was set, but no src/env.ts or src/env.js file could be found'
	);
}

if (this.inStyleAttributeWithoutInterpolation(attributeContext, document.getText())) {
    const [start, end] = attributeContext.valueRange;
    return this.getCompletionsInternal(
        document,
        position,
        new StyleAttributeDocument(document, start, end, this.cssLanguageServices)
    );
} else {
    return getIdClassCompletion(this.getCSSDoc(document), attributeContext);
}

for (const root of this.workspaceRoot) {
    for (const filePath of filesToWatch.split(',')) {
        if (!filePath.includes('*')) {
            paths.add(filePath);
            continue;
        }

        const normalizedPath = normalizePath(join(root, filePath));
        includePatterns.add(normalizedPath);
        const pathSegments = normalizedPath.split('**');
        let directory = pathSegments[0] || '.';
        paths.add(directory);
    }
}

if (originalTagInfo && transpiledTagInfo) {
    const sourceLength = originalTagInfo.container.end - originalTagInfo.container.start;
    const transpiledLength =
        transpiledTagInfo.container.end - transpiledTagInfo.container.start;
    const diff = sourceLength - transpiledLength;

    return new SvelteFragmentMapper(
        { end: transpiledTagInfo.container.end, diff },
        new FragmentMapper(originalDoc.getText(), originalTagInfo, originalDoc.uri),
        new FragmentMapper(transpiled, transpiledTagInfo, originalDoc.uri),
        sourceMapper
    );
}

switch (item.kind) {
    case ts.ScriptElementKind.interfaceElement:
        return this.getSymbolRange(tsDoc, item);

    case ts.ScriptElementKind.classElement:
    case ts.ScriptElementKind.memberFunctionElement:
    case ts.ScriptElementKind.memberVariableElement:
    case ts.ScriptElementKind.memberGetAccessorElement:
    case ts.ScriptElementKind.memberSetAccessorElement:
        if (item.kindModifiers.match(/\babstract\b/g)) {
            return this.getSymbolRange(tsDoc, item);
        }
        break;
}

if (candidate.error) {
    const catchKeyword = candidate.pending.skip && candidate.then.skip ? 'catch' : ':catch';

    const catchStart = content.lastIndexOf(catchKeyword, candidate.error.start);

    ranges.push([catchStart, catchStart + catchKeyword.length]);
} else if (!candidate.catch.skip) {
    // {:catch}

    const catchStart = content.indexOf(':catch', candidate.catch.start);

    ranges.push([catchStart, catchStart + ':catch'.length]);
}

if (tsconfigPath) {
    const info = ensureTsConfigInfoUpToDate(tsconfigPath);
    // tsconfig is either found from file-system or passed from svelte-check
    // so this is already be validated to exist
    if (!info) {
        throw new Error('Failed to get tsconfig: ' + tsconfigPath);
    }
    compilerOptions = info.parsedCommandLine.options;
    parsedConfig = info.parsedCommandLine;
    extendedConfigPaths = info.extendedConfigPaths;
} else {
    const config = parseDefaultCompilerOptions();
    compilerOptions = config.compilerOptions;
    parsedConfig = config.parsedConfig;
}

if (!configWatchers.has(tsconfigPath) && tsconfigPath) {
    configFileModifiedTime.set(tsconfigPath, tsSystem.getModifiedTime?.(tsconfigPath));
    configWatchers.set(
        tsconfigPath,
        // for some reason setting the polling interval is necessary, else some error in TS is thrown
        tsSystem.watchFile(tsconfigPath, watchConfigCallback, 1000)
    );
}

const cacheMonitorProxy = {
    ...docContext.extendedConfigCache,
    get(key: string) {
        extendedConfigPaths.add(key);
        return extendedConfigCache.get(key);
    },
    has(key: string) {
        extendedConfigPaths.add(key);
        return extendedConfigCache.has(key);
    },
    set(key: string, value: ts.ExtendedConfigCacheEntry) {
        extendedConfigPaths.add(key);
        return extendedConfigCache.set(key, value);
    }
};

const filenames = fileNames.map((name) => {
    if (!isSvelteFilepath(name)) {
        return name;
    }
    // We need to trick TypeScript into thinking that Svelte files
    // are either TS or JS files in order to generate correct d.ts
    // definition files.
    const isTsFile = svelteMap.add(name);
    return name + (isTsFile ? '.ts' : '.js');
});

if (moduleScriptTag) {
    moduleAst = createModuleAst(str, moduleScriptTag);

    if (moduleScriptTag.start != 0) {
        //move our module tag to the top
        str.move(moduleScriptTag.start, moduleScriptTag.end, 0);
    } else {
        //since our module script was already at position 0, we need to move our instance script tag to the end of it.
        instanceScriptTarget = moduleScriptTag.end;
    }
}

if (ts.isNamedExports(exportClause)) {
    for (const ne of exportClause.elements) {
        if (ne.propertyName) {
            this.addExport(ne.propertyName, false, ne.name, undefined, undefined, true);
        } else {
            this.addExport(ne.name, false, undefined, undefined, undefined, true);
        }
    }
    //we can remove entire statement
    this.removeExport(node.getStart(), node.end);
}

if (ts.isExpressionStatement(node.statement)) {
    if (isAssignmentBinaryExpr(node.statement.expression)) {
        return node.statement.expression;
    }
    if (
        ts.isParenthesizedExpression(node.statement.expression) &&
        isAssignmentBinaryExpr(node.statement.expression.expression)
    ) {
        return node.statement.expression.expression;
    }
}

for (const child of node.statements) {
    if (ts.isVariableStatement(child)) {
        const variable = child.declarationList.declarations.find(
            (declaration) =>
                ts.isIdentifier(declaration.name) && declaration.name.text === identifierName
        );
        if (variable) {
            return variable;
        }
    }
}

const segmentKeydownHandlers = {
			day: handleDaySegmentKeydown,
			month: handleMonthSegmentKeydown,
			year: handleYearSegmentKeydown,
			hour: handleHourSegmentKeydown,
			minute: handleMinuteSegmentKeydown,
			second: handleSecondSegmentKeydown,
			dayPeriod: handleDayPeriodSegmentKeydown,
			timeZoneName: handleTimeZoneSegmentKeydown,
		} as const;

for (const new_cookie of cookies) {
	const { name, value, options } = new_cookie;
	headers.append('set-cookie', serialize(name, value, options));

	// special case — for routes ending with .html, the route data lives in a sibling
	// `.html__data.json` file rather than a child `/__data.json` file, which means
	// we need to duplicate the cookie
	if (options.path.endsWith('.html')) {
		const path = add_data_suffix(options.path);
		headers.append('set-cookie', serialize(name, value, { ...options, path }));
	}
}

const vite_plugin_svelte_options = {
	configFile: false,
	extensions: svelte_config.extensions,
	preprocess,
	onwarn: svelte_config.onwarn,
	compilerOptions: {
		// @ts-ignore - ignore this property when running `pnpm check` against Svelte 5 in the ecosystem CI
		hydratable: isSvelte5Plus() ? undefined : true,
		...svelte_config.compilerOptions
	},
	...svelte_config.vitePlugin
};

for (const config of tsconfigDependencies) {
    if (dependedConfigWatchers.has(config)) {
        continue;
    }

    configFileModifiedTime.set(config, tsSystem.getModifiedTime?.(config));
    dependedConfigWatchers.set(
        config,
        // for some reason setting the polling interval is necessary, else some error in TS is thrown
        tsSystem.watchFile(config, createWatchDependedConfigCallback(docContext), 1000)
    );
}

const snapshot = DocumentSnapshot.fromDocument(document, {
        parse: document.compiler?.parse,
        version: document.compiler?.VERSION,
        transformOnTemplateError: false,
        typingsNamespace: 'svelteHTML',
        emitJsDoc: true,
        rewriteExternalImports: options?.rewriteExternalImports
    } satisfies SvelteSnapshotOptions) as SvelteDocumentSnapshot;

const rewriteExternalImportsOptions: RewriteExternalImportsOptions | undefined =
        options.rewriteExternalImports && options.filename
            ? {
                  sourcePath: options.filename,
                  generatedPath: options.rewriteExternalImports.generatedPath,
                  workspacePath: options.rewriteExternalImports.workspacePath
              }
            : undefined;

(
        [
            [TokenModifier.declaration, SemanticTokenModifiers.declaration],
            [TokenModifier.static, SemanticTokenModifiers.static],
            [TokenModifier.async, SemanticTokenModifiers.async],
            [TokenModifier.readonly, SemanticTokenModifiers.readonly],
            [TokenModifier.defaultLibrary, SemanticTokenModifiers.defaultLibrary],
            [TokenModifier.local, 'local']
        ] as const
    ).forEach(([tsModifier, legend]) => (tokenModifiers[tsModifier] = legend));
